contracts/AccessControl.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./PatientRegistry.sol";

/// @title AccessControl
/// @notice Manages doctor access requests to patient records.
///         Doctors request access → patient approves/rejects on-chain →
///         access auto-expires after a set duration.
///         Every action is permanently logged via events.
contract AccessControl {

    // ─── Structs ────────────────────────────────────────────────────────────

    enum AccessStatus { Pending, Approved, Rejected, Expired }

    struct AccessRequest {
        address doctor;
        address patient;
        uint256 requestedAt;
        uint256 approvedAt;
        uint256 expiresAt;       // 0 if not yet approved
        AccessStatus status;
        string  purpose;         // e.g. "Cardiology consultation"
    }

    // ─── State ──────────────────────────────────────────────────────────────

    PatientRegistry private registry;

    /// @dev Unique request ID counter
    uint256 private requestCounter;

    /// @dev requestId → AccessRequest
    mapping(uint256 => AccessRequest) private requests;

    /// @dev patient → doctor → latest requestId (for quick lookup)
    mapping(address => mapping(address => uint256)) private latestRequest;

    /// @dev All request IDs for a given patient (for enumeration)
    mapping(address => uint256[]) private patientRequests;

    /// @dev All request IDs made by a given doctor
    mapping(address => uint256[]) private doctorRequests;

    /// @dev Default access duration: 30 days
    uint256 public constant DEFAULT_ACCESS_DURATION = 30 days;

    // ─── Events ─────────────────────────────────────────────────────────────

    event AccessRequested(uint256 indexed requestId, address indexed doctor, address indexed patient, string purpose, uint256 timestamp);
    event AccessApproved (uint256 indexed requestId, address indexed doctor, address indexed patient, uint256 expiresAt);
    event AccessRejected (uint256 indexed requestId, address indexed doctor, address indexed patient, uint256 timestamp);
    event AccessRevoked  (uint256 indexed requestId, address indexed doctor, address indexed patient, uint256 timestamp);

    // ─── Constructor ────────────────────────────────────────────────────────

    constructor(address _registryAddress) {
        registry = PatientRegistry(_registryAddress);
    }

    // ─── Modifiers ──────────────────────────────────────────────────────────

    modifier onlyRegisteredPatient(address _addr) {
        require(registry.isRegistered(_addr), "Not a registered patient");
        _;
    }

    modifier onlyPendingRequest(uint256 _requestId) {
        require(requests[_requestId].status == AccessStatus.Pending, "Request is not pending");
        _;
    }

    modifier onlyPatientOfRequest(uint256 _requestId) {
        require(requests[_requestId].patient == msg.sender, "Not the patient for this request");
        _;
    }

    // ─── Doctor Actions ─────────────────────────────────────────────────────

    /// @notice Doctor requests access to a patient's records
    /// @param _patient  Address of the patient
    /// @param _purpose  Plain-text reason (e.g. "Pre-surgery review")
    function requestAccess(
        address _patient,
        string calldata _purpose
    ) external onlyRegisteredPatient(_patient) returns (uint256 requestId) {
        require(msg.sender != _patient, "Cannot request access to own records");

        requestCounter++;
        requestId = requestCounter;

        requests[requestId] = AccessRequest({
            doctor:      msg.sender,
            patient:     _patient,
            requestedAt: block.timestamp,
            approvedAt:  0,
            expiresAt:   0,
            status:      AccessStatus.Pending,
            purpose:     _purpose
        });

        latestRequest[_patient][msg.sender] = requestId;
        patientRequests[_patient].push(requestId);
        doctorRequests[msg.sender].push(requestId);

        emit AccessRequested(requestId, msg.sender, _patient, _purpose, block.timestamp);
    }

    // ─── Patient Actions ────────────────────────────────────────────────────

    /// @notice Patient approves a pending access request
    /// @param _requestId     The request to approve
    /// @param _durationSecs  How long to grant access (0 = use default 30 days)
    function approveAccess(uint256 _requestId, uint256 _durationSecs)
        external
        onlyPendingRequest(_requestId)
        onlyPatientOfRequest(_requestId)
    {
        uint256 duration = _durationSecs == 0 ? DEFAULT_ACCESS_DURATION : _durationSecs;
        uint256 expiry   = block.timestamp + duration;

        AccessRequest storage req = requests[_requestId];
        req.status     = AccessStatus.Approved;
        req.approvedAt = block.timestamp;
        req.expiresAt  = expiry;

        emit AccessApproved(_requestId, req.doctor, req.patient, expiry);
    }

    /// @notice Patient rejects a pending access request
    function rejectAccess(uint256 _requestId)
        external
        onlyPendingRequest(_requestId)
        onlyPatientOfRequest(_requestId)
    {
        AccessRequest storage req = requests[_requestId];
        req.status = AccessStatus.Rejected;
        emit AccessRejected(_requestId, req.doctor, req.patient, block.timestamp);
    }

    /// @notice Patient revokes a previously approved access at any time
    function revokeAccess(uint256 _requestId) external onlyPatientOfRequest(_requestId) {
        AccessRequest storage req = requests[_requestId];
        require(req.status == AccessStatus.Approved, "Access not currently approved");
        req.status    = AccessStatus.Expired;
        req.expiresAt = block.timestamp; // mark as expired now
        emit AccessRevoked(_requestId, req.doctor, req.patient, block.timestamp);
    }

    // ─── View Functions ─────────────────────────────────────────────────────

    /// @notice Check if a doctor currently has valid (approved + not expired) access
    function hasValidAccess(address _doctor, address _patient) external view returns (bool) {
        uint256 rid = latestRequest[_patient][_doctor];
        if (rid == 0) return false;
        AccessRequest storage req = requests[rid];
        return (
            req.status    == AccessStatus.Approved &&
            block.timestamp < req.expiresAt
        );
    }

    /// @notice Get full details of a request
    function getRequest(uint256 _requestId) external view returns (AccessRequest memory) {
        return requests[_requestId];
    }

    /// @notice Get all request IDs for a patient (so they can review pending requests)
    function getPatientRequests(address _patient) external view returns (uint256[] memory) {
        return patientRequests[_patient];
    }

    /// @notice Get all request IDs made by a doctor
    function getDoctorRequests(address _doctor) external view returns (uint256[] memory) {
        return doctorRequests[_doctor];
    }
}

contracts/EmergencyAccess.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./PatientRegistry.sol";

/// @title EmergencyAccess
/// @notice Allows pre-authorised emergency responders to access patient
///         records without waiting for patient approval — but with a
///         strict time limit and a fully public on-chain log.
///         Patients pre-register trusted emergency contacts / hospitals.
///         Every emergency access event is permanently visible on-chain.
contract EmergencyAccess {

    // ─── State ──────────────────────────────────────────────────────────────

    PatientRegistry private registry;

    /// @dev Emergency access duration: 6 hours
    uint256 public constant EMERGENCY_DURATION = 6 hours;

    /// @dev patient → set of pre-approved emergency responder addresses
    mapping(address => mapping(address => bool)) private trustedResponders;

    struct EmergencyEvent {
        uint256 eventId;
        address responder;
        address patient;
        uint256 accessedAt;
        uint256 expiresAt;
        string  reason;      // e.g. "Cardiac arrest — ER admission"
        bool    isActive;
    }

    uint256 private eventCounter;
    mapping(uint256 => EmergencyEvent) private events;

    /// @dev responder → patient → latest eventId
    mapping(address => mapping(address => uint256)) private activeEvent;

    // ─── Events ─────────────────────────────────────────────────────────────

    event ResponderTrusted  (address indexed patient, address indexed responder, uint256 timestamp);
    event ResponderRemoved  (address indexed patient, address indexed responder, uint256 timestamp);
    event EmergencyAccessed (uint256 indexed eventId, address indexed responder, address indexed patient, string reason, uint256 expiresAt);
    event EmergencyExpired  (uint256 indexed eventId, uint256 timestamp);

    // ─── Constructor ────────────────────────────────────────────────────────

    constructor(address _registryAddr) {
        registry = PatientRegistry(_registryAddr);
    }

    // ─── Patient: Manage Trusted Responders ─────────────────────────────────

    /// @notice Patient pre-authorises an emergency responder (e.g. a hospital ER)
    function addTrustedResponder(address _responder) external {
        require(registry.isRegistered(msg.sender), "Not a registered patient");
        require(_responder != msg.sender,           "Cannot add yourself");
        trustedResponders[msg.sender][_responder] = true;
        emit ResponderTrusted(msg.sender, _responder, block.timestamp);
    }

    /// @notice Patient removes a previously trusted responder
    function removeTrustedResponder(address _responder) external {
        trustedResponders[msg.sender][_responder] = false;
        emit ResponderRemoved(msg.sender, _responder, block.timestamp);
    }

    /// @notice Check if a responder is trusted by a patient
    function isTrustedResponder(address _patient, address _responder) external view returns (bool) {
        return trustedResponders[_patient][_responder];
    }

    // ─── Emergency Responder: Invoke Emergency Access ────────────────────────

    /// @notice Invoke emergency access to a patient's records.
    ///         Caller must be a pre-approved trusted responder.
    ///         Access is time-limited to 6 hours and logged forever.
    function invokeEmergencyAccess(address _patient, string calldata _reason)
        external
        returns (uint256 eventId)
    {
        require(registry.isRegistered(_patient),          "Patient not registered");
        require(trustedResponders[_patient][msg.sender],  "Not a trusted responder for this patient");
        require(bytes(_reason).length > 0,                "Reason required");

        eventCounter++;
        eventId = eventCounter;

        uint256 expiry = block.timestamp + EMERGENCY_DURATION;

        events[eventId] = EmergencyEvent({
            eventId:    eventId,
            responder:  msg.sender,
            patient:    _patient,
            accessedAt: block.timestamp,
            expiresAt:  expiry,
            reason:     _reason,
            isActive:   true
        });

        activeEvent[msg.sender][_patient] = eventId;

        emit EmergencyAccessed(eventId, msg.sender, _patient, _reason, expiry);
    }

    // ─── View Functions ─────────────────────────────────────────────────────

    /// @notice Check if a responder currently has valid emergency access
    function hasEmergencyAccess(address _responder, address _patient) external view returns (bool) {
        uint256 eid = activeEvent[_responder][_patient];
        if (eid == 0) return false;
        EmergencyEvent storage e = events[eid];
        return (e.isActive && block.timestamp < e.expiresAt);
    }

    /// @notice Get details of an emergency event (fully public — transparency by design)
    function getEmergencyEvent(uint256 _eventId) external view returns (EmergencyEvent memory) {
        return events[_eventId];
    }

    /// @notice Total emergency access events ever invoked
    function totalEvents() external view returns (uint256) {
        return eventCounter;
    }
}

contracts/PatientRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/// @title PatientRegistry
/// @notice Registers patients on-chain. Each patient is identified by their
///         Ethereum wallet address. Only the patient themselves can register
///         or update their own profile.
contract PatientRegistry {

    // ─── Structs ────────────────────────────────────────────────────────────

    struct Patient {
        address walletAddress;
        string  name;           // stored off-chain in production; here for demo
        uint256 dateOfBirth;    // Unix timestamp
        string  bloodType;      // e.g. "O+"
        bool    isRegistered;
        uint256 registeredAt;   // block timestamp of registration
    }

    // ─── State ──────────────────────────────────────────────────────────────

    /// @dev Maps patient wallet address → Patient struct
    mapping(address => Patient) private patients;

    /// @dev All registered patient addresses (for enumeration)
    address[] private patientAddresses;

    // ─── Events ─────────────────────────────────────────────────────────────

    event PatientRegistered(address indexed patient, uint256 timestamp);
    event PatientUpdated(address indexed patient, uint256 timestamp);

    // ─── Modifiers ──────────────────────────────────────────────────────────

    modifier onlyUnregistered() {
        require(!patients[msg.sender].isRegistered, "Already registered");
        _;
    }

    modifier onlyRegistered(address _addr) {
        require(patients[_addr].isRegistered, "Patient not registered");
        _;
    }

    // ─── Functions ──────────────────────────────────────────────────────────

    /// @notice Register yourself as a patient
    /// @param _name        Full name (keep minimal in production — use IPFS)
    /// @param _dateOfBirth Unix timestamp of date of birth
    /// @param _bloodType   Blood type string e.g. "A+"
    function register(
        string calldata _name,
        uint256 _dateOfBirth,
        string calldata _bloodType
    ) external onlyUnregistered {
        patients[msg.sender] = Patient({
            walletAddress: msg.sender,
            name:          _name,
            dateOfBirth:   _dateOfBirth,
            bloodType:     _bloodType,
            isRegistered:  true,
            registeredAt:  block.timestamp
        });

        patientAddresses.push(msg.sender);
        emit PatientRegistered(msg.sender, block.timestamp);
    }

    /// @notice Update your own profile fields
    function updateProfile(
        string calldata _name,
        string calldata _bloodType
    ) external onlyRegistered(msg.sender) {
        Patient storage p = patients[msg.sender];
        p.name      = _name;
        p.bloodType = _bloodType;
        emit PatientUpdated(msg.sender, block.timestamp);
    }

    /// @notice Check whether an address is a registered patient
    function isRegistered(address _addr) external view returns (bool) {
        return patients[_addr].isRegistered;
    }

    /// @notice Fetch a patient's basic profile (only the patient or an
    ///         authorised caller should call this — enforce in AccessControl)
    function getPatient(address _addr)
        external
        view
        onlyRegistered(_addr)
        returns (
            address walletAddress,
            string memory name,
            uint256 dateOfBirth,
            string memory bloodType,
            uint256 registeredAt
        )
    {
        Patient storage p = patients[_addr];
        return (p.walletAddress, p.name, p.dateOfBirth, p.bloodType, p.registeredAt);
    }

    /// @notice Total number of registered patients
    function totalPatients() external view returns (uint256) {
        return patientAddresses.length;
    }
}

contracts/RecordRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./PatientRegistry.sol";
import "./AccessControl.sol";

/// @title RecordRegistry
/// @notice Stores IPFS content hashes of encrypted medical records on-chain.
///         The actual file lives on IPFS (encrypted with the patient's public key).
///         The blockchain only holds the hash, metadata, and who uploaded it.
///         Only authorised doctors (approved via AccessControl) or the patient
///         themselves may read the record index.
contract RecordRegistry {

    // ─── Structs ────────────────────────────────────────────────────────────

    enum RecordType { Lab, Prescription, Imaging, Discharge, Vaccination, Other }

    struct MedicalRecord {
        uint256     recordId;
        address     patient;
        address     uploadedBy;   // doctor or hospital wallet
        string      ipfsHash;     // CIDv1 content address on IPFS
        RecordType  recordType;
        string      description;  // short plain-text label
        uint256     uploadedAt;
        bool        isValid;      // false if record was retracted
    }

    // ─── State ──────────────────────────────────────────────────────────────

    PatientRegistry private registry;
    AccessControl   private accessControl;

    uint256 private recordCounter;

    /// @dev recordId → MedicalRecord
    mapping(uint256 => MedicalRecord) private records;

    /// @dev patient address → list of their record IDs
    mapping(address => uint256[]) private patientRecords;

    /// @dev ipfsHash → recordId (prevent duplicate uploads)
    mapping(string => uint256) private hashToRecord;

    // ─── Events ─────────────────────────────────────────────────────────────

    event RecordUploaded(
        uint256 indexed recordId,
        address indexed patient,
        address indexed uploadedBy,
        string  ipfsHash,
        RecordType recordType,
        uint256 timestamp
    );

    event RecordRetracted(
        uint256 indexed recordId,
        address indexed patient,
        uint256 timestamp
    );

    // ─── Constructor ────────────────────────────────────────────────────────

    constructor(address _registryAddr, address _accessControlAddr) {
        registry      = PatientRegistry(_registryAddr);
        accessControl = AccessControl(_accessControlAddr);
    }

    // ─── Modifiers ──────────────────────────────────────────────────────────

    modifier onlyRegisteredPatient(address _addr) {
        require(registry.isRegistered(_addr), "Not a registered patient");
        _;
    }

    /// @dev Caller must be the patient OR a doctor with valid access
    modifier onlyAuthorised(address _patient) {
        bool isSelf   = (msg.sender == _patient);
        bool hasAccess = accessControl.hasValidAccess(msg.sender, _patient);
        require(isSelf || hasAccess, "Not authorised to access this patient's records");
        _;
    }

    // ─── Write Functions ────────────────────────────────────────────────────

    /// @notice Upload a new medical record for a patient.
    ///         Can be called by the patient themselves or an authorised doctor.
    /// @param _patient      Patient wallet address
    /// @param _ipfsHash     IPFS CID of the encrypted file
    /// @param _recordType   Enum category of the record
    /// @param _description  Short label e.g. "Blood panel 2024-04"
    function uploadRecord(
        address    _patient,
        string     calldata _ipfsHash,
        RecordType _recordType,
        string     calldata _description
    )
        external
        onlyRegisteredPatient(_patient)
        onlyAuthorised(_patient)
        returns (uint256 recordId)
    {
        require(bytes(_ipfsHash).length > 0,     "IPFS hash required");
        require(hashToRecord[_ipfsHash] == 0,    "Record already uploaded");

        recordCounter++;
        recordId = recordCounter;

        records[recordId] = MedicalRecord({
            recordId:    recordId,
            patient:     _patient,
            uploadedBy:  msg.sender,
            ipfsHash:    _ipfsHash,
            recordType:  _recordType,
            description: _description,
            uploadedAt:  block.timestamp,
            isValid:     true
        });

        patientRecords[_patient].push(recordId);
        hashToRecord[_ipfsHash] = recordId;

        emit RecordUploaded(recordId, _patient, msg.sender, _ipfsHash, _recordType, block.timestamp);
    }

    /// @notice Patient can retract (invalidate) a record — does NOT delete
    ///         from IPFS, just marks it as invalid on-chain so UIs can hide it.
    function retractRecord(uint256 _recordId) external {
        MedicalRecord storage r = records[_recordId];
        require(r.patient == msg.sender,  "Only the patient can retract");
        require(r.isValid,                "Already retracted");
        r.isValid = false;
        emit RecordRetracted(_recordId, msg.sender, block.timestamp);
    }

    // ─── Read Functions ─────────────────────────────────────────────────────

    /// @notice Get a single record (caller must be patient or authorised doctor)
    function getRecord(uint256 _recordId)
        external
        view
        onlyAuthorised(records[_recordId].patient)
        returns (MedicalRecord memory)
    {
        return records[_recordId];
    }

    /// @notice Get all record IDs for a patient
    function getPatientRecordIds(address _patient)
        external
        view
        onlyAuthorised(_patient)
        returns (uint256[] memory)
    {
        return patientRecords[_patient];
    }

    /// @notice Verify a record's integrity: check that an IPFS hash matches
    ///         what is stored on-chain (anyone can call this — public trust).
    function verifyRecord(uint256 _recordId, string calldata _ipfsHash)
        external
        view
        returns (bool isMatch, bool isValid)
    {
        MedicalRecord storage r = records[_recordId];
        isMatch = keccak256(bytes(r.ipfsHash)) == keccak256(bytes(_ipfsHash));
        isValid = r.isValid;
    }

    /// @notice Total records ever uploaded (across all patients)
    function totalRecords() external view returns (uint256) {
        return recordCounter;
    }
}

